// Función para validar CIF/NIF español
function validarCifNif(numero) {
  // Eliminar espacios y convertir a mayúsculas
  numero = numero.trim().toUpperCase();

  // Expresión regular para validar formato
  const regexNIF = /^[0-9]{8}[TRWAGMYFPDXBNJZSQVHLCKE]$/i;
  const regexCIF = /^[ABCDEFGHJKLMNPQRSUVW][0-9]{7}[0-9A-J]$/i;

  // Verificar si es un NIF
  if (regexNIF.test(numero)) {
    // Algoritmo para validar NIF
    const letras = 'TRWAGMYFPDXBNJZSQVHLCKE';
    const numero_sin_letra = numero.substring(0, 8);
    const letra = numero.charAt(8);
    const posicion = parseInt(numero_sin_letra) % 23;
    const letra_calculada = letras.charAt(posicion);

    if (letra === letra_calculada) {
      return {
        valido: true,
        tipo: 'NIF',
        mensaje: 'NIF válido'
      };
    } else {
      return {
        valido: false,
        tipo: 'NIF',
        mensaje: `NIF inválido. La letra correcta debería ser ${letra_calculada}`
      };
    }
  }

  // Verificar si es un CIF
  if (regexCIF.test(numero)) {
    // Algoritmo para validar CIF
    const letra_inicial = numero.charAt(0);
    const digitos = numero.substring(1, 8);
    const control = numero.charAt(8);

    // Calcular dígito de control
    let suma_a = 0;
    let suma_b = 0;

    for (let i = 0; i < digitos.length; i++) {
      const digito = parseInt(digitos.charAt(i));

      if (i % 2 === 0) {
        // Posiciones pares
        const temp = digito * 2;
        suma_a += temp < 10 ? temp : temp - 9;
      } else {
        // Posiciones impares
        suma_b += digito;
      }
    }

    const suma_total = suma_a + suma_b;
    const unidad = suma_total % 10;
    const digito_control = unidad === 0 ? 0 : 10 - unidad;

    // Verificar si el control es una letra o un número
    const letras_control = 'JABCDEFGHI';
    const es_letra_control = isNaN(parseInt(control));

    if (es_letra_control) {
      // Control es una letra
      if (control === letras_control.charAt(digito_control)) {
        return {
          valido: true,
          tipo: 'CIF',
          mensaje: 'CIF válido'
        };
      } else {
        return {
          valido: false,
          tipo: 'CIF',
          mensaje: `CIF inválido. El control correcto debería ser ${letras_control.charAt(digito_control)}`
        };
      }
    } else {
      // Control es un número
      if (parseInt(control) === digito_control) {
        return {
          valido: true,
          tipo: 'CIF',
          mensaje: 'CIF válido'
        };
      } else {
        return {
          valido: false,
          tipo: 'CIF',
          mensaje: `CIF inválido. El control correcto debería ser ${digito_control}`
        };
      }
    }
  }

  // Si no coincide con ningún formato
  return {
    valido: false,
    tipo: 'Desconocido',
    mensaje: 'Formato de CIF/NIF no válido'
  };
}

// Procesar la entrada
const numero = $input.item.json.numero;

if (!numero) {
  return {
    json: {
      error: 'Se requiere un número de CIF/NIF'
    }
  };
}

const resultado = validarCifNif(numero);

return {
  json: resultado
};

