// Función para validar los datos de una factura
function validarFactura(datos) {
  const {
    baseImponible,
    porcentajeIva,
    importeIva,
    totalFactura,
    recargo = 0,
    porcentajeRecargo = 0
  } = datos;

  // Redondear a 2 decimales para evitar problemas de precisión
  const redondear = (valor) => Math.round(valor * 100) / 100;

  // Calcular valores esperados
  const ivaEsperado = redondear(baseImponible * porcentajeIva / 100);
  const recargoEsperado = redondear(baseImponible * porcentajeRecargo / 100);
  const totalEsperado = redondear(baseImponible + ivaEsperado + recargoEsperado);

  // Verificar IVA
  const ivaValido = Math.abs(ivaEsperado - importeIva) < 0.01;

  // Verificar recargo si está presente
  const recargoValido = recargo === 0 || Math.abs(recargoEsperado - recargo) < 0.01;

  // Verificar total
  const totalValido = Math.abs(totalEsperado - totalFactura) < 0.01;

  // Preparar resultado
  const resultado = {
    valido: ivaValido && recargoValido && totalValido,
    errores: [],
    valores_calculados: {
      iva_calculado: ivaEsperado,
      recargo_calculado: recargoEsperado,
      total_calculado: totalEsperado
    }
  };

  // Añadir errores específicos
  if (!ivaValido) {
    resultado.errores.push({
      campo: 'importeIva',
      mensaje: `El IVA no es correcto. Debería ser ${ivaEsperado.toFixed(2)}€ (${porcentajeIva}% de ${baseImponible.toFixed(2)}€)`
    });
  }

  if (!recargoValido && recargo > 0) {
    resultado.errores.push({
      campo: 'recargo',
      mensaje: `El recargo no es correcto. Debería ser ${recargoEsperado.toFixed(2)}€ (${porcentajeRecargo}% de ${baseImponible.toFixed(2)}€)`
    });
  }

  if (!totalValido) {
    resultado.errores.push({
      campo: 'totalFactura',
      mensaje: `El total no es correcto. Debería ser ${totalEsperado.toFixed(2)}€ (${baseImponible.toFixed(2)}€ + ${ivaEsperado.toFixed(2)}€ + ${recargoEsperado.toFixed(2)}€)`
    });
  }

  return resultado;
}

// Procesar la entrada
const datos = {
  baseImponible: $input.item.json.baseImponible,
  porcentajeIva: $input.item.json.porcentajeIva,
  importeIva: $input.item.json.importeIva,
  totalFactura: $input.item.json.totalFactura,
  recargo: $input.item.json.recargo || 0,
  porcentajeRecargo: $input.item.json.porcentajeRecargo || 0
};

// Validar que todos los campos requeridos estén presentes
const camposRequeridos = ['baseImponible', 'porcentajeIva', 'importeIva', 'totalFactura'];
const camposFaltantes = camposRequeridos.filter(campo => datos[campo] === undefined);

if (camposFaltantes.length > 0) {
  return {
    json: {
      valido: false,
      errores: [{
        campo: 'general',
        mensaje: `Faltan los siguientes campos requeridos: ${camposFaltantes.join(', ')}`
      }]
    }
  };
}

// Validar que los valores sean numéricos
for (const campo in datos) {
  if (datos[campo] !== undefined && isNaN(datos[campo])) {
    return {
      json: {
        valido: false,
        errores: [{
          campo,
          mensaje: `El campo ${campo} debe ser un número`
        }]
      }
    };
  }
}

const resultado = validarFactura(datos);

return {
  json: resultado
};
